import subprocess, re, json
from tools import TOOLS

SYSTEM = """You are a research assistant with these tools:
{tool_list}

To use a tool, write EXACTLY: ACTION: tool_name("input")
Then wait for OBSERVATION.
When you have enough information, write: FINAL ANSWER: your concise answer.

Always search before answering. Use 1-3 tool calls max."""

def make_system_prompt():
    tool_list = "\n".join(f"- {name}: {t['desc']}" for name, t in TOOLS.items())
    return SYSTEM.format(tool_list=tool_list)

def call_model(messages, model="llama3.2:3b"):
    prompt = "\n".join(f"{m['role']}: {m['content']}" for m in messages)
    r = subprocess.run(
        ["ollama", "run", model, prompt],
        capture_output=True, text=True, timeout=120
    )
    return r.stdout.strip()

def run_agent(question, max_steps=4):
    messages = [
        {"role": "system", "content": make_system_prompt()},
        {"role": "user", "content": question}
    ]
    for step in range(max_steps):
        reply = call_model(messages)
        print(f"\n--- Step {step+1} ---\n{reply}")

        if "FINAL ANSWER:" in reply:
            return reply.split("FINAL ANSWER:", 1)[1].strip()

        match = re.search(r'ACTION:\s*(\w+)\("(.+?)"\)', reply)
        if not match:
            return reply  # model didn't follow format, return raw

        tool_name, tool_input = match.group(1), match.group(2)
        if tool_name in TOOLS:
            result = TOOLS[tool_name]["fn"](tool_input)
            messages.append({"role": "assistant", "content": reply})
            messages.append({"role": "user", "content": f"OBSERVATION: {result}"})
        else:
            messages.append({"role": "user", "content": f"OBSERVATION: Unknown tool '{tool_name}'"})

    return "Agent reached max steps without a final answer."

