// popup.js
document.getElementById('summarize').addEventListener('click', async () => {
  const btn = document.getElementById('summarize');
  const result = document.getElementById('result');
  btn.disabled = true;
  result.className = 'loading';
  result.textContent = 'Extracting page text...';

  try {
    const [tab] = await chrome.tabs.query({ active: true, currentWindow: true });
    const [{ result: pageText }] = await chrome.scripting.executeScript({
      target: { tabId: tab.id },
      func: () => document.body.innerText.substring(0, 4000)
    });

    if (!pageText || pageText.trim().length < 50) {
      result.textContent = 'Not enough text on this page to summarize.';
      btn.disabled = false;
      return;
    }

    result.textContent = 'Sending to local AI model...';
    const resp = await fetch('http://localhost:11434/api/generate', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        model: 'llama3.2:3b',
        prompt: `Summarize this webpage in 3-5 bullet points. Focus on key facts and takeaways. Be concise.\n\nPage text:\n${pageText}`,
        stream: false
      })
    });

    const data = await resp.json();
    result.className = '';
    result.textContent = data.response || 'No response from model.';
  } catch (err) {
    result.className = '';
    result.textContent = `Error: ${err.message}\n\nMake sure Ollama is running:\n  ollama serve`;
  }
  btn.disabled = false;
});

